public class MessageSequenceComparator implements Comparator<Message<?>>, Serializable {

	@Override
	public int compare(Message<?> o1, Message<?> o2) {
		int sequenceNumber1 = new IntegrationMessageHeaderAccessor(o1).getSequenceNumber();
		int sequenceNumber2 = new IntegrationMessageHeaderAccessor(o2).getSequenceNumber();

		return Integer.compare(sequenceNumber1, sequenceNumber2);
	}

}

@Component
public class HashGenerator {

    public String generateSubscriptionKeyFieldsHash(final SubscriptionBase subscription) {
        final Hasher hasher = Hashing.md5()
                .newHasher()
                .putString(subscription.getOwningApplication(), UTF_8)
                .putString(subscription.getConsumerGroup(), UTF_8);
        subscription.getEventTypes()
                .stream()
                .sorted()
                .forEach(et -> hasher.putString(et, UTF_8));
        return hasher.hash().toString();
    }

}

